+export async function stopWebChatServer() {
+  if (!state) return;
+  gatewayReady = false;
+  gateway?.stop();
+  gateway = null;
+  if (wss) {
+    for (const client of wss.clients) {
+      try {
+        client.close();
+      } catch {
+        /* ignore */
+      }
+    }
+    await new Promise<void>((resolve) => wss?.close(() => resolve()));
+  }
+  if (state.server) {
+    await new Promise<void>((resolve) => state?.server.close(() => resolve()));
+  }
+  wss = null;
+  wsSessions.clear();
+  state = null;
+}
